const W=Math.min(innerWidth,480),H=innerHeight;class S extends Phaser.Scene{create(){this.add.rectangle(W/2,H/2,W,H,0x161616);this.ground=this.add.rectangle(W/2,H-30,W,20,0x666);this.physics.add.existing(this.ground,true);this.blocks=this.physics.add.group();this.score=0;this.ui=this.add.text(10,10,'Stack:0');this.input.on('pointerdown',p=>{if(this.over)return;const b=this.add.rectangle(p.x,40,50,20,0x93c5fd);this.physics.add.existing(b);this.blocks.add(b);this.physics.add.collider(b,this.ground);this.physics.add.collider(b,this.blocks);this.score++;this.ui.setText('Stack:'+this.score);if(this.score>=15)this.end('CLEAR');});this.r=this.input.keyboard.addKey('R');}end(m){this.over=true;this.add.text(W/2,H/2,m+'\nR',{align:'center'}).setOrigin(.5);}update(){if(this.r.isDown)this.scene.restart();}}
new Phaser.Game({type:Phaser.AUTO,parent:'game',width:W,height:H,physics:{default:'arcade'},scene:[S]});
